+    // WITNESS (0x0A)
+    if let Some(c) = input.witness_chain {
+        out.extend_from_slice(&rvf_wire::write_segment(0x0A, c, flags, sid)); sid += 1;
+    }
+    // DiffPrivacyProof (0x34)
